import{_ as o,o as n,c as s,ae as i}from"./chunks/framework.C8MNLDzb.js";const m=JSON.parse('{"title":"《论语》名句","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/mingju/jing/论语.md","filePath":"docs/sucai/mingju/jing/论语.md"}'),r={name:"docs/sucai/mingju/jing/论语.md"};function a(l,t,e,g,_,c){return n(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="《论语》名句" tabindex="-1">《论语》名句 <a class="header-anchor" href="#《论语》名句" aria-label="Permalink to &quot;《论语》名句&quot;">​</a></h1><ol><li><strong>学而时习之，不亦说乎？</strong> —— 学习知识后时常复习，不是很快乐吗？（《论语·学而》）</li><li><strong>吾十有五而志于学，三十而立，四十而不惑，五十而知天命，六十而耳顺，七十而从心所欲，不逾矩。</strong> —— 我十五岁立志学习，三十岁能立足于世，四十岁能不被迷惑，五十岁能知天命，六十岁能听进逆耳之言，七十岁能随心所欲却又不越规矩。（《论语·为政》）</li><li><strong>温故而知新，可以为师矣。</strong> —— 温习旧知识能有新收获，就可以当老师了。（《论语·为政》）</li><li><strong>知之为知之，不知为不知，是知也。</strong> —— 知道就是知道，不知道就是不知道，这才是真正的智慧。（《论语·为政》）</li><li><strong>学而不思则罔，思而不学则殆。</strong> —— 只学习不思考就会迷惑，只思考不学习就会精神疲惫。（《论语·为政》）</li><li><strong>君子周而不比，小人比而不周。</strong> —— 君子团结而不勾结，小人勾结而不团结。（《论语·为政》）</li><li><strong>人而无信，不知其可也。</strong> —— 人如果不讲信用，不知道还能做什么。（《论语·为政》）</li><li><strong>《关雎》乐而不淫，哀而不伤。</strong> —— 《关雎》快乐而不放荡，悲哀而不伤痛。（《论语·八佾》）</li><li><strong>里仁为美，择不处仁，焉得知？</strong> —— 居住在有仁德的地方才是美好的，不选择有仁德的地方居住，怎能算是明智呢？（《论语·里仁》）</li><li><strong>君子喻于义，小人喻于利。</strong> —— 君子明白大义，小人只懂得小利。（《论语·里仁》）</li></ol>',2)])])}const u=o(r,[["render",a]]);export{m as __pageData,u as default};
